import React, { Component } from 'react'

class Pagination extends Component {


  previous_page=()=>{
    if(this.props.previous>0)
    return(
        <span className="custom-pagination" onClick={(e)=>this.props.getByPage(this.props.previous)} aria-label="Previous">
          &laquo;
        </span>
    )
  }


  next_page=()=>{
    if(this.props.next>0)
    return(
        <span className="custom-pagination" onClick={(e)=>this.props.getByPage(this.props.next)} aria-label="Next">
          &raquo;
        </span>
    )
  }


  pagination_items=()=>{
    var pagination=[];
    if(this.props.pages>0)
    for (let i=1;i<=this.props.pages;i++)
      pagination.push(
        <span className={(i==this.props.page)?"custom-pagination active" : "custom-pagination"} onClick={(e)=>this.props.getByPage(i)}>{i}</span>
      )
      return pagination
  }


  render() {
    return (
      <div className="my-4 text-center container">

          {this.previous_page()}
          {/* {this.pagination_items()} */}
          {this.next_page()}

      </div>
    )
  }
}

export default Pagination
