import React, { Component } from 'react'
import { faPrint,faImage,faStar} from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import Comments from "../Comments";
import Note from "../Note";

class List extends Component {

  days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
  get_commercial_color=(visites)=>{
    if (visites<100) return "text-danger"
    if ((visites>=100) && (visites<120)) return "text-warning"
    if (visites>=120) return "text-green"
  }
  raport_image2=(image)=>{
    if (image!=null)
    return(
      <a href={image} target="_blank" className="d-block">
        <small>image2</small>
      </a>
    )
  }
  get_stars=(note)=>{
    var table = []

    for (var i = 0; i < parseInt(note); i++)
      table.push(<small><FontAwesomeIcon icon={faStar} /></small>)

    if (note==0)
    return (<small>add note</small>)
    else
    return table
  }
  render() {
    return (
      <React.Fragment>
        <div className="container py-2 text-secondary">
            affichage de <b>({this.props.length})</b> rapports <b>({this.props.visitesLen})</b> visites <b>({this.props.medecinsLen})</b> clients
             <span dangerouslySetInnerHTML={{__html:this.props.other}}></span>
            &nbsp; <a className="btn" href={this.props.pdflink().replace("PDF", "IMAGE")} target="_blank"><FontAwesomeIcon icon={faImage} /></a>
            &nbsp; <a className="btn" href={this.props.pdflink()} target="_blank"><FontAwesomeIcon icon={faPrint} /></a>

        </div>
      <div className="container-fluid">
        <table className="table table-bordered table-striped table-hover">
          <thead>
            <tr>
              <th scope="col">date</th>
              <th scope="col">délégué</th>
              <th scope="col">region</th>
              <th scope="col">priorité</th>
              <th scope="col">rapport</th>
            </tr>
          </thead>
          <tbody>
          {this.props.rapports.map(rapport=>(
            <tr key={rapport.id}>
              <th scope="row" className={rapport.tasks.length==0 && rapport.visites.length == 0 && "bg-dangerr"}> <small>{this.days[new Date(rapport.added).getDay()]} {rapport.added}</small> &nbsp;  <br/>
              <a href={`/admin/rapports/rapport/${rapport.id}/change/`} target={"_blank"}>
                  <b>ID</b>:({rapport.id})
              </a><br/>
              <a href={rapport.image} target="_blank">
              <img style={{maxHeight:100,marginTop:7}} src={rapport.image}/>
              </a>
              {this.raport_image2(rapport.image2)}
              </th>
              <td>
              <small> {rapport.commercial.nom} {rapport.commercial.prenom}</small> <br/> <small>
              {rapport.commercial.telephone} </small> <br/>
              <small>{rapport.commercial.email}</small> <br/>
              <small className={this.get_commercial_color(rapport.commercial.visites_month)}>
              ({rapport.commercial.visites_month}) visites ce mois <br/>
              <span dangerouslySetInnerHTML={{__html:rapport.commercial.other_details}}></span>

              </small>
              </td>

              <td>
              <small><b>{rapport.commercial.pays}</b></small> <br/>
              {rapport.visites.map(visite=>(
              <small key={visite.id}> {visite.commune} </small>
              ))}

              </td>

              <td>{rapport.visites.map(visite=>(
                <small key={visite.id}><b>{visite.priorite},</b></small>
              ))}</td>

              <td className="text-secondary" >
              <small dangerouslySetInnerHTML={{__html:rapport.details}}></small>
              <a className="btn" href={`/rapports/PDF/${rapport.id}`} target="__blank"><FontAwesomeIcon icon={faPrint} /></a>
              <br/>
              <Note rapport={rapport} />
              <small>{rapport.observation}</small><br/>
              <Comments rapport={rapport}/>

              </td>
            </tr>
          ))}

          </tbody>
        </table>
      </div>
      </React.Fragment>
    )
  }
}
//
export default List
