import React, { Component } from 'react'

class List extends Component {

  render() {
    return (
      <React.Fragment>
        <div className="container py-2 text-secondary"> affichage de {this.props.length} resultats</div>
      <div className="container-fluid">
        <table className="table table-bordered table-striped table-hover">
          <thead>
            <tr>
              <th scope="col">email</th>
              <th scope="col">telephone</th>
              <th scope="col">region</th>
              <th scope="col">nom</th>
              <th scope="col">rapports</th>
              <th scope="col">visites</th>
            </tr>
          </thead>
          <tbody>
          {this.props.commerciaux.map(commercial=>(
            <tr key={commercial.id}>
              <td scope="col">{commercial.email}</td>
              <td scope="col">{commercial.telephone}</td>
              <td scope="col">{commercial.region}</td>
              <td scope="col">{commercial.nom}</td>
              <td scope="col">{commercial.rapports}</td>
              <td scope="col">{commercial.visites_details}</td>
            </tr>
          ))}

          </tbody>
        </table>
      </div>
      </React.Fragment>
    )
  }
}
//
export default List
